// UFPR - Residencia Medica 2021 (Editais 55/2021-HC, 53/2021-HT), Acesso Direto, prova objetiva
export const UFPR_2021_102_QUESTIONS: any[] = [
  { id: 'ufpr_2021_102_001', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Cirurgia Geral', text: 'Qual é o substrato gliconeogênico da fase inicial do jejum?', options: ['Glicogênio.', 'Corpo cetônico.', 'Carboidrato complexo.', 'Proteína.', 'Ácido graxo.'], correctIndex: 3 },
  { id: 'ufpr_2021_102_002', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Cirurgia Geral', text: 'O produto do metabolismo anaeróbico periférico da glicose nas situações de injúria e trauma, que se torna substrato para o Ciclo de Cori no fígado, é:', options: ['adenosina trifosfato.', 'frutose – 6 – fosfato.', 'lactato.', 'glutamina.', 'riboflavina.'], correctIndex: 2 },
  { id: 'ufpr_2021_102_003', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Cirurgia Geral', text: 'A fase proliferativa da cicatrização de uma ferida, com predomínio entre o 4.º e 14.º dia, tem como protagonista central a população de fibroblastos presentes no local e sua produção de moléculas estimulada por vários fatores de crescimento. Considere as seguintes moléculas: 1. Colágeno Tipo III. 2. Colágeno Tipo I. 3. Fibronectina. 4. Glicosaminoglicanos. É/São produto(s) dos fibroblastos durante a fase proliferativa de cicatrização:', options: ['4 apenas.', '1 e 2 apenas.', '2 e 3 apenas.', '1, 3 e 4 apenas.', '1, 2, 3 e 4.'], correctIndex: 3 },
  { id: 'ufpr_2021_102_004', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Cirurgia Geral', text: 'Citocina fundamental na cicatrização das feridas, produzida por monócitos e linfócitos, estimula a proliferação de fibroblastos e é fator quimiotático para neutrófilos e macrófagos. O texto se refere à/ao:', options: ['fator de crescimento de transformação – Beta (TGF-beta).', 'fator de necrose tumoral – Alfa (TNF- alfa).', 'interleucina – 1 (IL-1).', 'fator de crescimento epidérmico (EGF).', 'fator de crescimento derivado das plaquetas (PDGF).'], correctIndex: 1 },
  { id: 'ufpr_2021_102_005', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Cirurgia Geral', text: 'A respeito de nutrição em cirurgia, assinale a alternativa correta.', options: ['O metabolismo basal está aumentado em traumas e diminuído em até 25% no jejum prolongado.', 'Perda involuntária superior a 20% do peso corporal nos últimos 6 meses pré-operatórios deve ser interpretada como sinal de desnutrição.', 'Em pacientes cirúrgicos gravemente desnutridos, a terapia nutricional é frequentemente obrigatória e deve ser iniciada o mais precocemente possível no período pós-operatório.', 'Na intolerância à glicose durante terapia nutricional parenteral, recomenda-se a substituição de até 50% das calorias ofertadas por calorias advindas de emulsões lipídicas.', 'Albumina sérica abaixo de 3 g/dL, independentemente da causa, está associada ao aumento significativo da morbidade e da mortalidade de doentes hospitalizados.'], correctIndex: 4 },
  { id: 'ufpr_2021_102_006', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Cirurgia Geral', text: 'Infecção em cirurgia é tema de domínio obrigatório quando se pretende controlar e reduzir morbidade e mortalidade relacionadas a processos infecciosos, envolvendo vários e diferentes aspectos do período perioperatório. A respeito do assunto, considere as seguintes afirmativas: 1. A infecção decorrente de complicação de um procedimento cirúrgico é definida como infecção cirúrgica. 2. A infecção que necessita de procedimento cirúrgico para ser tratada é definida como infecção cirúrgica. 3. Resistência a antibióticos é fator influenciador da ocorrência de infecção cirúrgica ligado ao hospedeiro. 4. Vírus não são considerados como agentes de infecção cirúrgica. Assinale a alternativa correta.', options: ['Somente a afirmativa 1 é verdadeira.', 'Somente as afirmativas 1 e 2 são verdadeiras.', 'Somente as afirmativas 3 e 4 são verdadeiras.', 'Somente as afirmativas 2, 3 e 4 são verdadeiras.', 'As afirmativas 1, 2, 3 e 4 são verdadeiras.'], correctIndex: 1 },
  { id: 'ufpr_2021_102_007', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Cirurgia Geral', text: 'Para a maioria dos pacientes que necessitam terapia nutricional, as estimativas geralmente utilizadas das necessidades calóricas e proteicas são, respectivamente:', options: ['25 a 30 Kcal/kg/dia e 0,8 a 1,8 g/kg/dia.', '25 a 30 Kcal/kg/dia e 2,5 a 3,5 g/kg/dia.', '35 a 40 Kcal/kg/dia e 0,8 a 1,8 g/kg/dia.', '35 a 40 Kcal/kg/dia e 2,5 a 3,5 g/kg/dia.', '45 a 50 Kcal/kg/dia e 2,5 a 3,5 g/kg/dia.'], correctIndex: 0 },
  { id: 'ufpr_2021_102_008', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Cirurgia Geral', text: 'Paciente feminina, 24 anos, portadora de estenose mitral, será submetida a valvoplastia, sem troca valvar, através de esternotomia e circulação extracorpórea. Nessa operação, cuja incisão cirúrgica é classificada como da categoria "limpa", o uso de antibioticoprofilaxia:', options: ['não está indicado, pois a ferida cirúrgica oferecerá baixo risco de infecção (<1%).', 'não está indicado, pois não será inserida prótese valvar mitral, apenas se realizará ação sobre a valva.', 'está indicado, pois um advento de infecção seria muito grave.', 'está indicado, pois se trata de paciente com risco aumentado de infecção.', 'não está indicado, pois a paciente não se enquadra em risco aumentado para infecção.'], correctIndex: 2 },
  { id: 'ufpr_2021_102_009', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Cirurgia Geral', text: 'A condição clínica mais frequentemente relacionada à oclusão arterial aguda dos membros é:', options: ['infarto agudo do miocárdio.', 'aterosclerose.', 'fibrilação atrial.', 'insuficiência cardíaca congestiva.', 'policitemia vera.'], correctIndex: 2 },
  { id: 'ufpr_2021_102_010', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Cirurgia Geral', text: 'O pneumotórax espontâneo secundário é assim classificado quando as lesões evidenciadas na radiografia de tórax ou na tomografia computadorizada podem ser identificadas como responsáveis pela sua ocorrência. A condição clínica mais frequentemente relacionada a essa complicação é:', options: ['neoplasia maligna primária.', 'metástase pulmonar secundária.', 'fibrose pulmonar.', 'doença pulmonar intersticial.', 'doença pulmonar obstrutiva crônica.'], correctIndex: 4 },
  { id: 'ufpr_2021_102_011', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Cirurgia Geral', text: 'Paciente feminina, 52 anos, portadora de colelitíase com indicação de tratamento cirúrgico (colecistectomia videolaparoscópica), vem à consulta pré-operatória. Além do quadro clínico típico da colelitíase, a paciente nega qualquer outro sintoma ou histórico relevante. A bateria de exames complementares pré-operatórios dessa paciente deve ser composta de: (VG=Volume Globular; Hb=Hemoglobina; ECG=Eletrocardiograma)', options: ['VG/Hb + RX de Tórax', 'VG/Hb + ECG.', 'VG/Hb + ECG + Creatinina.', 'VG/Hb + Creatinina + Glicemia.', 'VG/Hb + Creatinina + RX de Tórax.'], correctIndex: 1 },
  { id: 'ufpr_2021_102_012', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Cirurgia Geral', text: 'A hérnia abdominal mais comum na mulher e a hérnia abdominal mais comum no homem são, respectivamente:', options: ['inguinal indireta e femoral.', 'femoral e inguinal indireta.', 'inguinal direta e inguinal direta.', 'inguinal indireta e inguinal indireta.', 'femoral e inguinal direta.'], correctIndex: 3 },
  { id: 'ufpr_2021_102_013', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Cirurgia Geral', text: 'Tanto a hérnia de Richter quanto a hérnia de Littré são mais caracterizadas pelo conteúdo do seu saco herniário do que propriamente pelo local da parede abdominal por onde se exteriorizam. O conteúdo típico do saco herniário da hérnia de Richter e o conteúdo típico do saco herniário da hérnia de Littré são, respectivamente:', options: ['apêndice epiploico e apêndice vermiforme.', 'apêndice vermiforme e divertículo de Meckel.', 'divertículo de Meckel e borda antimesentérica de alça intestinal.', 'borda antimesentérica de alça intestinal e divertículo de Meckel.', 'divertículo de Meckel e apêndice epiploico.'], correctIndex: 3 },
  { id: 'ufpr_2021_102_014', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Cirurgia Geral', text: 'A respeito dos fatores etiopatogênicos das neoplasias malignas do esôfago, assinale a alternativa correta.', options: ['O megaesôfago chagásico não é fator de risco para o carcinoma epidermoide do esôfago.', 'O esôfago de Barrett é fator de risco para o carcinoma espinocelular do esôfago.', 'A queratose familiar palmar e plantar não é fator de risco para o adenocarcinoma do esôfago.', 'A síndrome de Plummer-Vinson é fator de risco para o adenocarcinoma do esôfago.', 'A estenose cáustica do esôfago não é fator de risco para o carcinoma espinocelular do esôfago.'], correctIndex: 2 },
  { id: 'ufpr_2021_102_015', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Cirurgia Geral', text: 'No que diz respeito a pancreatite crônica, a causa mais comum entre os adultos e a causa mais comum entre as crianças são, respectivamente:', options: ['alcoólica e fibrose cística.', 'hereditária e idiopática.', 'idiopática e fibrose cística.', 'alcoólica e hereditária.', 'alcoólica e congênita (pancreas divisum).'], correctIndex: 0 },
  { id: 'ufpr_2021_102_016', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Cirurgia Geral', text: 'Sobre hemorragia digestiva, considere as seguintes afirmativas: 1. Ângulo de Treitz é o reparo anatômico que define o limite entre hemorragia digestiva alta e baixa. 2. Varizes de esôfago, úlcera péptica, diverticulose colônica e angiodisplasia perfazem 85% das hemorragias agudas. 3. Cerca de 85% dos casos de hemorragia digestiva aguda decorrem de sangramentos acima do Ângulo de Treitz. 4. O intestino delgado é o responsável por 5 a 8% das hemorragias agudas. Assinale a alternativa correta.', options: ['Somente a afirmativa 4 é verdadeira.', 'Somente as afirmativas 1 e 4 são verdadeiras.', 'Somente as afirmativas 2 e 3 são verdadeiras.', 'Somente as afirmativas 1, 2 e 3 são verdadeiras.', 'As afirmativas 1, 2, 3 e 4 são verdadeiras.'], correctIndex: 3 },
  { id: 'ufpr_2021_102_017', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Cirurgia Geral', text: 'Na hemorragia digestiva, melena é definida por fezes pastosas, de coloração preta e odor fétido. Essas características se devem à oxidação do heme por bactérias intestinais, indicando que a fonte do sangramento se encontra provavelmente:', options: ['acima do piloro.', 'acima do ângulo de Treitz.', 'nas alças do jejuno proximal.', 'acima da válvula ileocecal.', 'no ceco e início do cólon direito.'], correctIndex: 3 },
  { id: 'ufpr_2021_102_018', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Cirurgia Geral', text: 'No que diz respeito a abdome agudo e sua classificação, a categoria mais prevalente dessa síndrome é:', options: ['inflamatório/infeccioso.', 'obstrutivo.', 'perfurativo.', 'vascular.', 'hemorrágico.'], correctIndex: 0 },
  { id: 'ufpr_2021_102_019', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Cirurgia Geral', text: 'Em relação aos métodos diagnósticos de imagem no abdome agudo, assinale a alternativa correta.', options: ['O RX simples de abdome é superior à ecografia e à tomografia computadorizada no diagnóstico de pneumoperitônio.', 'A tomografia computadorizada é superior aos outros exames na detecção, no nível e na causa da oclusão intestinal.', 'Com as novas gerações de aparelhos de ecografia, o método não é mais dificultado por distensão gasosa.', 'O desempenho da ecografia na detecção do cálculo em posição ureteral não é suplantada por outro exame de imagem.', 'A tomografia computadorizada é melhor que a ecografia na detecção de colelitíase, mas o custo impede sua disseminação.'], correctIndex: 1 },
  { id: 'ufpr_2021_102_020', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Cirurgia Geral', text: 'Como é conhecida a condição clínica caracterizada por abdome agudo oclusivo (náusea, vômito, dor e distensão abdominais, parada da eliminação de gases e fezes) em que a radiografia simples do abdome mostra pneumobilia, alças intestinais distendidas, com padrão obstrutivo, e ausência de ar na ampola retal?', options: ['Íleo biliar.', 'Pneumatose intestinal aguda.', 'Colangiobilia oclusiva.', 'Oclusão intestinal aguda.', 'Abdome hepato-oclusivo.'], correctIndex: 0 },
  { id: 'ufpr_2021_102_021', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Neurologia', text: 'Em relação à migrânea, é correto afirmar:', options: ['O tipo mais comum é a migrânea com aura.', 'A localização mais comum da cefaleia é a holocraniana.', 'A idade de início mais frequente é após os 50 anos.', 'A presença de história familiar de migrânea é frequente.', 'A forma mais comum de aura é a sensorial.'], correctIndex: 3 },
  { id: 'ufpr_2021_102_022', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Clínica Médica', text: 'Paciente de 55 anos, sexo feminino, procura pronto atendimento com quadro de edema em membros inferiores, aumento do volume abdominal e falta de ar com início há quatro meses. Encontra-se em situação de vulnerabilidade social, dormindo todas as noites em abrigo para moradores de rua. Apresenta histórico de tabagismo ativo de 40 anos-maço, de etilismo ativo de 200 mL ao dia de bebida destilada e de PPD forte reator há um ano. Ao exame físico, destacam-se bulhas cardíacas hipofonéticas, ascite volumosa e edema de membros inferiores. Radiografia de tórax demonstra derrame pleural leve à direita e hiperinsuflação pulmonar bilateral. Ultrassonografia demonstra fígado com contornos irregulares e ascite. Ecodoppler de vasos hepáticos demonstra vasos hepáticos e veia porta dentro da normalidade. Dentre os exames laboratoriais, destacam-se: bilirrubina total = 2,7 mg/dL; tempo de protrombina/RNI = 1,5; albumina = 2,8 g/dL. Realiza-se paracentese diagnóstica, cuja análise do líquido ascítico demonstra: proteína total = 2,0 g/dL; albumina = 1,1 g/dL; contagem de leucócitos = 306 e 60% de polimorfonucleares. Considerando o caso clínico descrito, qual é a principal hipótese diagnóstica?', options: ['Tuberculose peritoneal.', 'Síndrome de Budd-Chiari.', 'Carcinomatose peritoneal.', 'Cirrose hepática alcoólica.', 'Peritonite bacteriana espontânea.'], correctIndex: 3 },
  { id: 'ufpr_2021_102_023', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Neurologia', text: 'Paciente de 24 anos, sexo feminino, procura assistência médica devido a três crises convulsivas ocorridas no intervalo de dois meses. Levando-se em consideração o desejo da paciente em engravidar, qual dos medicamentos abaixo tem o maior risco de teratogenicidade quando utilizado durante a gestação?', options: ['Ácido valproico.', 'Lamotrigina.', 'Levetiracetam.', 'Oxcarbazepina.', 'Topiramato.'], correctIndex: 0 },
  { id: 'ufpr_2021_102_024', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Dermatologia', text: 'Qual das características abaixo é um achado sugestivo da síndrome de Sweet?', options: ['Artrite de pequenas articulações.', 'Linfocitose atípica.', 'Início abrupto de nódulos ou placas eritematosas e dolorosas na pele.', 'Consolidação alveolar pulmonar com padrão migratório.', 'Telangectasias cutâneas.'], correctIndex: 2 },
  { id: 'ufpr_2021_102_025', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Reumatologia', text: 'Qual das doenças reumatológicas abaixo apresenta a maior associação com o fenômeno de Raynaud?', options: ['Artrite reumatoide.', 'Dermatomiosite.', 'Esclerose sistêmica.', 'Lúpus eritematoso sistêmico.', 'Síndrome de Sjögren.'], correctIndex: 2 },
  { id: 'ufpr_2021_102_026', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Infectologia', text: 'É um antibiótico da classe dos carbapenêmicos que deve ser evitado no tratamento de infecções causadas pela bactéria Pseudomonas aeruginosa:', options: ['ampicilina-sulbactam.', 'ertapenem.', 'imipenem.', 'meropenem.', 'piperacilina-tazobactam.'], correctIndex: 1 },
  { id: 'ufpr_2021_102_027', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Clínica Médica', text: 'Um paciente adulto em uso de varfarina realizou dosagem de Tempo de Atividade de Protrombina (TAP) que apresentou resultado de Relação Normatizada Internacional (RNI) igual a 8. O paciente não apresenta sangramento, equimoses ou hematomas. Nesse caso, a conduta correta a ser adotada é:', options: ['suspender a varfarina, administrar vitamina K intramuscular e reintroduzir varfarina quando o RNI estiver abaixo de 2.', 'reduzir a dose de varfarina em 50% e reavaliar o paciente ambulatorialmente em uma semana com novo TAP/RNI.', 'suspender a varfarina, administrar plasma fresco e reintroduzir varfarina com dose ajustada no dia seguinte.', 'reduzir a dose de varfarina em 25%, administrar vitamina K via oral e reavaliar o paciente em uma semana com novo TAP/RNI.', 'suspender a varfarina e monitorar o TAP/RNI, reintroduzindo a varfarina em dose reduzida, assim que o RNI voltar a faixa terapêutica indicada.'], correctIndex: 4 },
  { id: 'ufpr_2021_102_028', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Infectologia', text: 'Paciente de 55 anos, sexo feminino, em tratamento quimioterápico de câncer de mama avançado, procura o pronto atendimento por queixa de febre referida. Ela explica que a febre teve início no dia de hoje, uma semana após ter feito sua última sessão de quimioterapia. Na avaliação inicial, a paciente encontra-se hemodinamicamente estável, com temperatura axilar de 38,3 ºC, sem outras alterações ao exame físico. Os exames laboratoriais iniciais mostram leucopenia importante, com contagem absoluta de neutrófilos (CAN) de 100 células/mm3, sem outras alterações significativas. Você decide internar a paciente e iniciar antibioticoterapia empírica com cefepime. No 4.º dia de internação, a paciente encontra-se em bom estado geral, afebril há mais de 72 horas, sem outras queixas, com culturas negativas, com CAN de 560 células/mm3 nos dois últimos dias. Diante do exposto, qual é a conduta correta nesse momento?', options: ['Manter cefepime até completar 7 dias de tratamento antibiótico e realizar alta hospitalar após o término do tratamento antibiótico.', 'Suspender cefepime e realizar alta hospitalar para seguimento ambulatorial, com orientações sobre sinais de alerta e reavaliação de emergência se necessário.', 'Manter cefepime e associar filgrastim para acelerar a recuperação neutrofílica antes de realizar alta hospitalar.', 'Trocar cefepime por ciprofloxacino via oral e realizar alta hospitalar de forma que a paciente complete pelo menos 7 dias de tratamento antibiótico em regime ambulatorial.', 'Suspender cefepime e manter a paciente em regime de internação hospitalar para avaliação de curva térmica nas próximas 72 horas, com programação de realizar alta hospitalar se permanecer afebril.'], correctIndex: 1 },
  { id: 'ufpr_2021_102_029', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Infectologia', text: 'Paciente de 50 anos, sexo feminino, procura atendimento ambulatorial por lesão de pele em dorso da mão direita, três semanas após ter sido arranhada por um gato doente que encontrou na rua, o qual apresentava múltiplas lesões ulceradas de pele. Ela refere que a lesão provocada pela arranhadura inicial cicatrizou, porém nos últimos dias notou o aparecimento de lesões papulares no local, com formação de placa eritematosa infiltrada e posterior ulceração da lesão. Refere também que percebeu lesões nodulares mais profundas no antebraço e braço direito, ascendentes, aparentemente seguindo trajeto linfático ao exame físico. Diante do exposto, o provável diagnóstico e a indicação para o caso são, respectivamente:', options: ['doença da arranhadura do gato – tratamento empírico com azitromicina.', 'infecção secundária da lesão inicial por bactérias presentes na pele, como Staphylococcus aureus – tratamento empírico com cefalexina.', 'micobacteriose cutânea de transmissão animal – investigação complementar com biópsia para cultura e exame anátomopatológico para confirmação diagnóstica.', 'toxoplasmose por inoculação direta – sorologia IgG e IgM para toxoplasmose para confirmação diagnóstica.', 'provável esporotricose de transmissão felina – biópsia da lesão para cultura e exame anátomopatológico para confirmação diagnóstica.'], correctIndex: 4 },
  { id: 'ufpr_2021_102_030', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Hematologia', text: 'Paciente de 72 anos, sexo masculino, foi internado por anemia sintomática, com dosagem de hemoglobina sérica de 6 g/dL. O médico plantonista solicitou a transfusão de 3 unidades de concentrado de hemácias (CH) na tarde de hoje. Você é acionado(a) para reavaliar o paciente logo no início da transfusão da terceira unidade de CH por ele apresentar quadro de dispneia, iniciada durante a transfusão da segunda unidade de CH, com necessidade de oxigênio suplementar, associada a taquicardia e elevação da pressão arterial, sem febre ou outras queixas. Além da avaliação radiológica complementar, frente ao quadro clínico apresentado, o diagnóstico provável e a conduta correta são, respectivamente:', options: ['reação transfusional hemolítica – suspensão da transfusão e administração de metilprednisolona.', 'lesão pulmonar aguda associada à transfusão (TRALI) – suspensão da transfusão e administração de metilprednisolona.', 'congestão pulmonar associada à transfusão (TACO) – suspensão da transfusão e administração de diurético.', 'lesão pulmonar aguda associada à transfusão (TRALI) – administração de metilprednisolona e continuidade da transfusão.', 'congestão pulmonar associada à transfusão (TACO) – administração de diurético e continuidade da transfusão.'], correctIndex: 2 },
  { id: 'ufpr_2021_102_031', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Infectologia', text: 'Paciente de 30 anos, sexo masculino, internado há 10 dias por insuficiência renal aguda e em hemodiálise, apresentou quadro de febre, taquicardia e calafrios no início da manhã de ontem. Realizou-se coleta de hemoculturas das duas vias do cateter de diálise e de sangue periférico no mesmo momento, sendo que na manhã de hoje, às 08h00min, houve positivação de hemocultura coletada através do cateter e, às 11h00min, também houve positivação de hemocultura coletada de sangue periférico. Em ambas as coletas houve crescimento de cocos Gram-positivos agrupados, inicialmente identificados como Staphylococcus aureus, com resultado de antibiograma ainda pendente. Considerando o contexto clínico apresentado e o diagnóstico e tratamento de infecção de corrente sanguínea associada a cateter (ICSAC), assinale a alternativa correta.', options: ['Os horários de positivação das hemoculturas coletadas do cateter e de sangue periférico não corroboram a hipótese de ICSAC, sendo indicada a investigação de outros prováveis focos primários, como pulmão e urina, além do tratamento inicial com vancomicina.', 'Os horários de positivação das hemoculturas corroboram a hipótese de ICSAC, sendo indicada a troca do cateter de diálise, assim como antibioticoterapia com vancomicina até os resultados finais do antibiograma.', 'A definição ou não de ICSAC dependerá ainda do resultado da cultura de ponta de cateter, sendo indicada a troca do cateter de diálise e antibioticoterapia com vancomicina até os resultados finais do antibiograma.', 'Provavelmente trata-se de ICSAC, porém ainda não há indicação de remoção do cateter, sendo indicado apenas antibioticoterapia com tigeciclina até os resultados finais do antibiograma.', 'Os horários de positivação das hemoculturas não corroboram nem afastam a possibilidade de ICSAC, sendo indicado tratamento antibiótico com cefepime até o resultado do antibiograma, além de considerar a remoção do cateter se as hemoculturas permanecerem positivas após 72 horas de tratamento de antibiótico.'], correctIndex: 1 },
  { id: 'ufpr_2021_102_032', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Infectologia', text: 'Paciente de 70 anos, sexo feminino, internada para tratamento de neutropenia febril, passa a apresentar diarreia sem sangue, associada a leucocitose, no 5.º dia de internação hospitalar e de tratamento antibiótico com piperacilina-tazobactam. O médico assistente suspeita de diarreia por Clostridioides difficile e solicita exame de fezes para avaliação complementar. O resultado mostra pesquisa de GDH (glutamato desidrogenase) positiva e pesquisa de toxinas A e B negativas. Considerando o contexto clínico apresentado, é correto afirmar:', options: ['O exame de fezes afasta a hipótese de diarreia por C. difficile, sendo diarreia pelo antibiótico o provável diagnóstico, não sendo indicado tratamento específico neste momento.', 'O exame de fezes confirma a hipótese de diarreia por C. difficile, sendo indicado tratamento com metronidazol via oral.', 'O exame de fezes sugere a possibilidade de diarreia por C. difficile, sendo indicado tratamento com metronidazol ou vancomicina e administração conjunta de probióticos.', 'O exame de fezes não confirma a hipótese de diarreia por C. difficile, sendo indicada apenas a suspensão de piperacilina-tazobactam e tratamento com probióticos neste momento.', 'O exame de fezes não descarta a possibilidade de diarreia por C. difficile, sendo indicado tratamento com vancomicina via oral e suspensão de piperacilina-tazobactam assim que possível.'], correctIndex: 4 },
  { id: 'ufpr_2021_102_033', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Dermatologia', text: 'Paciente de 25 anos, sexo feminino, previamente hígida, procura atendimento relatando aparecimento de lesões nodulares, eritematosas, bastante dolorosas em face anterior das pernas, há 3 dias. Refere ainda febre não aferida e prostração. A principal hipótese diagnóstica e a conduta são, respectivamente:', options: ['infecção bacteriana de pele e partes moles – tratamento empírico com cefalexina.', 'vasculite idiopática – teste terapêutico com corticoesteroides.', 'calcifilaxia – investigação com paratormônio, dosagem de vitamina D e cálcio livre urinário.', 'eritema nodoso – tratamento com anti-inflamatório não esteroidal e investigação de fatores desencadeantes.', 'neuropatia periférica – tratamento com pregabalina.'], correctIndex: 3 },
  { id: 'ufpr_2021_102_034', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Cardiologia', text: 'Em relação ao tratamento da hipertensão arterial sistêmica, qual é o diurético tiazídico de escolha dentre todas as drogas dessa classe, tendo em vista seu maior tempo de meia-vida plasmática e sua maior evidência científica na redução de eventos cardiovasculares?', options: ['Amilorida.', 'Indapamida.', 'Clortalidona.', 'Hidroclorotiazida.', 'Triantereno.'], correctIndex: 2 },
  { id: 'ufpr_2021_102_035', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Pneumologia', text: 'Considerando o diagnóstico de tromboembolismo pulmonar (TEP) agudo, assinale a alternativa que contém um caso clínico de paciente em condição de receber tratamento ambulatorial do TEP com anticoagulante via oral.', options: ['Sexo feminino, 50 anos, adenocarcinoma invasor de mama com metástase óssea, pressão arterial 128/86 mmHg, frequência cardíaca de 88 bpm, frequência respiratória 14 irpm, saturação 80% em ar ambiente e saturação 95% com cateter nasal 3L/minuto.', 'Sexo masculino, 60 anos, história prévia de doença pulmonar intersticial, pressão arterial 70/40 mmHg, frequência cardíaca de 120 bpm, frequência respiratória 18 irpm e saturação 95% em ar ambiente.', 'Sexo feminino, 20 anos, portadora de síndrome do anticorpo antifosfolípide, em uso contínuo regular de varfarina, mantendo dor a despeito de morfina endovenosa, pressão arterial 124/82 mmHg, frequência cardíaca de 76 bpm, frequência respiratória 16 irpm e saturação 98% em ar ambiente.', 'Sexo feminino, 60 anos, cirurgia ortopédica recente em joelho direito, pressão arterial 118/78 mmHg, frequência cardíaca de 98 bpm, frequência respiratória 20 irpm, saturação 95% em ar ambiente, dosagem de troponina sérica normal e angiotomografia de tórax com ventrículo direito com dimensão menor que o ventrículo esquerdo.', 'Sexo masculino, 85 anos, doente renal crônico em hemodiálise, portador de insuficiência cardíaca e cirrose por doença gordurosa não alcóolica, pressão arterial 100/70 mmHg, frequência cardíaca de 120 bpm, frequência respiratória 32 irpm e saturação 80 % em ar ambiente.'], correctIndex: 3 },
  { id: 'ufpr_2021_102_036', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Cardiologia', text: 'Risco residual em doença arterial coronariana refere-se ao risco elevado de recorrência de eventos cardiovasculares, como infarto ou morte cardiovascular, em pacientes com coronariopatia, apesar da utilização de terapia otimizada com estatina de alta potência e antiplaquetários. Por isso, há diversos estudos sendo realizados sobre novas terapias para redução desse risco. A droga que tem se mostrado promissora em ensaios clínicos randomizados na redução do risco residual tanto em paciente com doença arterial coronariana estável quanto em paciente com síndrome coronariana aguda recente é:', options: ['metotrexate.', 'colchicina.', 'leflunomida.', 'infliximabe.', 'rituximabe.'], correctIndex: 1 },
  { id: 'ufpr_2021_102_037', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Reumatologia', text: 'É uma droga utilizada no tratamento de hipertensão arterial sistêmica que deve ser evitada em paciente com diagnóstico de gota:', options: ['hidroclorotiazida.', 'enalapril.', 'losartana.', 'anlodipino.', 'ramipril.'], correctIndex: 0 },
  { id: 'ufpr_2021_102_038', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Cardiologia', text: 'Paciente feminina, 52 anos, portadora de cardiopatia chagásica com disfunção ventricular sistólica (fração de ejeção de 21% no último ecocardiograma), procurou atendimento ambulatorial. Não apresenta histórico de diabetes ou doença renal crônica. Em uso de carvedilol 3,125 mg de 12/12 horas, sacubitril-valsartana 97/103 mg de 12/12 horas, espironolactona 25 mg pela manhã e furosemida 40 mg pela manhã, todos os dias. Relatou que nesta semana foi andando à padaria próxima de sua casa e precisou parar ao andar uma quadra na subida, e que também teve dispneia ao andar mais de três quadras em terreno plano. Nega ortopneia ou dispneia paroxística noturna. Ao exame físico, apresenta pressão arterial de 110/70 mmHg, frequência cardíaca de 51 bpm, saturação de 98% em ar ambiente, jugulares não ingurgitadas, ausculta cardíaca e pulmonar dentro da normalidade, sem edema de membros inferiores. Considerando o caso clínico descrito, para realizar o ajuste terapêutico deve-se:', options: ['aumentar furosemida para 40 mg pela manhã e 40 mg à tarde.', 'aumentar carvedilol para 6,25 mg de 12/12 horas.', 'iniciar ivabradina 5 mg 12/12 horas.', 'manter a prescrição atual, pois a paciente encontra-se compensada ao repouso.', 'iniciar inibidor do cotransportador sódio-glicose 2 (iSGLT2).'], correctIndex: 4 },
  { id: 'ufpr_2021_102_039', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Medicina Intensiva', text: 'Paciente de 68 anos, sexo feminino, com histórico de hipertensão e diabetes, procura a emergência por quadro de diarreia aquosa, com cerca de 10 episódios por dia, associada a náusea, vômitos e dor abdominal. Relata início dos sintomas há cinco dias. Ao exame físico: sinais de depleção do espaço extracelular, lúcida, Glasgow 15, pressão arterial de 80/40 mmHg, frequência cardíaca de 120 bpm, temperatura de 35,6 ºC, saturação de 92% em ar ambiente. Tempo de enchimento capilar prolongado, pulsos radiais finos, extremidades frias e pegajosas. Abdome: dor leve à palpação difusa, sem sinais de irritação peritoneal ou distensão. Ausculta pulmonar e cardíaca sem peculiaridades. Gasometria arterial em ar ambiente: pH 7,26, pCO2: 23 mmHg, Bic 10 mEq/L, pO2: 70 mmHg, SpO2: 92%, lactato 4 mmol/L, Na+: 128 mEq/L, Cl-: 105 mEq/L, K+: 3,0 mEq/L. Nenhuma terapia foi instituída até o momento. Segundo as definições atuais de sepse (SEPSIS-3), qual é a definição correta para o caso clínico apresentado?', options: ['Infecção não complicada.', 'Sepse.', 'Sepse grave.', 'Choque séptico.', 'Choque séptico refratário.'], correctIndex: 1 },
  { id: 'ufpr_2021_102_040', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Medicina Intensiva', text: 'Considerando o mesmo caso clínico da paciente de 68 anos com diarreia aquosa, hipotensa e taquicárdica, e a gasometria arterial: pH 7,26, pCO2: 23 mmHg, Bic 10 mEq/L, pO2: 70 mmHg, SpO2: 92%, lactato 4 mmol/L, Na+: 128 mEq/L, Cl-: 105 mEq/L, K+: 3,0 mEq/L, qual distúrbio é encontrado na interpretação da gasometria?', options: ['Acidose metabólica.', 'Alcalose metabólica.', 'Alcalose respiratória.', 'Acidose respiratória aguda.', 'Acidose respiratória crônica.'], correctIndex: 0 },
  { id: 'ufpr_2021_102_041', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Obstetrícia', text: 'Paciente de 22 anos, gestante de 28 semanas, vem à consulta de pré-natal com queixa de corrimento vaginal associado a odor fétido, de início há 7 dias. Nega coceira ou ardência. Ao exame especular, apresenta um conteúdo vaginal em pequena quantidade, branco-acinzentado, com finas bolhas. Com base no caso, é correto afirmar que a gestante com vaginose bacteriana:', options: ['tem esse diagnóstico com base no caso apresentado.', 'tem seu diagnóstico confirmado com o exame de Papanicolaou.', 'deve ser submetida aos critérios de Adolf e Jones para ajudar no diagnóstico.', 'deve receber a aplicação de 250 mg de ciprofloxacina em dose única.', 'apresenta fator de risco para desenvolvimento de trabalho de parto prematuro.'], correctIndex: 4 },
  { id: 'ufpr_2021_102_042', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Ginecologia', text: 'A densitometria óssea na mulher na menopausa deve ser solicitada quando houver:', options: ['idade superior a 55 anos.', 'história de fratura na infância por queda de nível.', 'evidências radiográficas de fratura.', 'história de puberdade precoce.', 'uso de cloridrato de venlafaxina.'], correctIndex: 2 },
  { id: 'ufpr_2021_102_043', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Ginecologia', text: 'É considerado um fator de risco para doença inflamatória pélvica (DIP):', options: ['idade inferior a 25 anos.', 'história familiar de DIP.', 'presença de varizes pélvicas.', 'laqueadura tubária como método contraceptivo.', 'infecção do trato urinário (ITU) de repetição.'], correctIndex: 0 },
  { id: 'ufpr_2021_102_044', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Ginecologia', text: 'Paciente de 47 anos vem ao pronto atendimento referindo sangramento vaginal iniciado há mais de 15 dias. Refere que há 6 meses apresenta irregularidade menstrual, com aumento da quantidade e duração da menstruação. Trouxe os seguintes exames: ecografia transvaginal, que mostra útero de 60 cm³, sem nodulações, endométrio regular com 10 mm de espessura, ovários sem alterações com 3,5 cm³ cada. Ao exame ginecológico: grande quantidade de sangue em vagina, colo uterino de aspecto normal. De acordo com a história clínica e o exame físico, é correto afirmar:', options: ['A primeira hipótese diagnóstica é de gravidez ectópica rota.', 'Coagulopatias devem ser investigadas.', 'Curetagem uterina de prova deve ser indicada como primeira opção de tratamento.', 'Sangramento uterino disfuncional por ciclos anovulatórios é a primeira hipótese diagnóstica.', 'Ressonância magnética pélvica deve ser solicitada para melhor avaliação de útero e ovários.'], correctIndex: 3 },
  { id: 'ufpr_2021_102_045', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Ginecologia', text: 'De acordo com estadiamento do câncer cervical da FIGO (Federação Internacional de Ginecologia e Obstetrícia) 2018, é correto afirmar:', options: ['Estadio IA2: profundida da invasão menor que 3 mm.', 'Estadio IIA1: carcinoma invasor com dimensões acima de 4 cm, envolvendo 1/3 superior de vagina sem envolvimento parametrial.', 'Estadio IIIC1: metástases em linfonodos pélvicos somente.', 'Estadio IIIB: carcinoma envolvendo 1/3 inferior de vagina, mas não parede pélvica.', 'Estadio IV B: disseminação para órgãos pélvicos adjacentes.'], correctIndex: 2 },
  { id: 'ufpr_2021_102_046', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Obstetrícia', text: 'Em relação às adaptações do organismo materno na gestação, é correto afirmar:', options: ['observa-se aumento volêmico mais discreto em pacientes que apresentam restrição de crescimento fetal e hipertensão arterial sistêmica.', 'existe um aumento da maioria dos elementos figurados do sangue na gravidez, porém o número de leucócitos não se altera em uma gravidez normal.', 'as adaptações cardiovasculares começam no terceiro trimestre de gestação.', 'ocorrem alterações em toda a cascata de coagulação, marcadamente com o número de plaquetas que se encontra aumentado.', 'ocorre uma queda na pressão arterial sistêmica, mais acentuada no terceiro trimestre de gestação.'], correctIndex: 0 },
  { id: 'ufpr_2021_102_047', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Obstetrícia', text: 'A placenta tem inúmeras funções, promovendo as trocas materno-fetais, garantindo as trocas gasosas, permitindo o transporte de nutrientes e assegurando a produção local de hormônios e enzimas. Sobre o desenvolvimento placentário, é correto afirmar:', options: ['O desenvolvimento dos vilos primários ocorre juntamente com a implantação do blastocisto, no sexto dia após a concepção.', 'As células trofoblásticas da placenta de primeiro trimestre são altamente invasivas, estendendo-se pelo endométrio até o miométrio e são responsáveis pela formação da placenta hemocoriônica.', 'O sistema de veias endometriais forma um plexo grosso com poucas anastomoses e fluxo de resistência elevado.', 'O processo de invasão trofoblástico das artérias espraiadas torna a resistência nos vasos placentários alta.', 'O transporte placentário ocorre exclusivamente por meio de difusão simples.'], correctIndex: 1 },
  { id: 'ufpr_2021_102_048', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Obstetrícia', text: 'O diagnóstico de trabalho de parto compreende a ocorrência de contrações uterinas e modificações cervicais. Em relação à assistência ao parto, assinale a alternativa correta.', options: ['O primeiro período do trabalho de parto consiste na dilatação cervical e descida do concepto e, durante essa fase, são imprescindíveis a punção venosa e o jejum absoluto.', 'A ocorrência de desacelerações precoces durante o primeiro período do trabalho de parto é acompanhada de hipóxia fetal e implicam a resolução imediata do parto.', 'As desacelerações tardias associam-se a diminuição do pH fetal e maior morbidade e mortalidade perinatal.', 'Os puxos (esforços explosivos) devem ser encorajados no primeiro período do trabalho de parto independentemente da dilatação cervical.', 'A monitorização contínua da frequência cardíaca fetal durante o primeiro período do trabalho de parto em gestações de risco habitual apresenta benefícios clínicos evidentes na assistência ao parto, com melhores resultados perinatais em comparação à ausculta intermitente.'], correctIndex: 2 },
  { id: 'ufpr_2021_102_049', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Obstetrícia', text: 'A hemorragia pós-parto constitui importante causa de morbimortalidade materna. Sobre essa situação, é correto afirmar:', options: ['A atonia uterina compreende a principal causa de hemorragia pós-parto e o seu manejo passa por medidas farmacológicas e cirúrgicas.', 'A ocorrência de parto precipitado não constitui fator de risco para hemorragia puerperal.', 'Após a realização de manobras de compressão e drogas uterotônicas, a histerectomia puerperal é a primeira medida a ser tomada nos casos de hemorragia puerperal.', 'Em virtude do aumento da volemia materna, as perdas sanguíneas da hemorragia puerperal raramente acarretam alterações hemodinâmicas maternas.', 'O diagnóstico de restos planetários é de pouca importância na assistência aos casos de hemorragia puerperal.'], correctIndex: 0 },
  { id: 'ufpr_2021_102_050', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Obstetrícia', text: 'A ocorrência do parto prematuro acarreta grande aumento da morbimortalidade perinatal e constitui um grave problema de saúde pública. Em relação à prematuridade, assinale a alternativa correta.', options: ['Medidas de predição e prevenção de prematuridade são difíceis de serem instituídas por serem de etiologia multifatorial.', 'As drogas tocolíticas apresentam alta eficácia e poucos efeitos colaterais.', 'A escolha da via de parto independe da apresentação fetal no parto pré-termo.', 'A amniorrexis prematura pré-termo não representa risco para a ocorrência de prematuridade.', 'A prematuridade terapêutica representa a maioria dos casos de parto prematuro.'], correctIndex: 0 },
  { id: 'ufpr_2021_102_051', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Mastologia', text: 'Devido à sua prevalência, o câncer de mama determina um grande empenho da comunidade científica em definir as melhores condições de rastreamento e detecção da doença. A mamografia exerce um papel fundamental na detecção precoce do câncer de mama, cuja incidências mínimas preconizadas são:', options: ['Póstero-anterior (PA) e perfil.', 'Crânio-caudal (CC) e médio lateral oblíqua (MLO).', 'Elkund.', 'Magnificação e compressão focal.', 'Crânio-caudal (CC) e perfil.'], correctIndex: 1 },
  { id: 'ufpr_2021_102_052', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Mastologia', text: 'O Breast Image Reporting and Data System (BIRADS) auxilia na padronização e divide os achados em categorias. A categoria que se refere a achados provavelmente benignos é:', options: ['0.', '1.', '2.', '3.', '6.'], correctIndex: 3 },
  { id: 'ufpr_2021_102_053', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Mastologia', text: 'A mastalgia é classificada quanto à origem em verdadeira (proveniente do tecido mamário) ou referida (extra-mamária, geralmente proveniente da parede torácica). A mastalgia verdadeira ainda pode ser subdividida em cíclica e acíclica. Sobre a mastalgia cíclica, é correto afirmar:', options: ['Pode acontecer em mulheres na pós-menopausa.', 'Exames de imagem complementares são necessários na ausência de alterações no exame físico.', 'A utilização de implantes mamários pode aumentar a incidência de mastalgia cíclica.', 'Tamoxifeno pode ser usado em casos refratários a analgésicos e anti-inflamatorios.', 'A amenorreia induzida por SIU hormonal evita mastalgia cíclica.'], correctIndex: 3 },
  { id: 'ufpr_2021_102_054', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Mastologia', text: 'Reconhecer os quadros clínicos e realizar o diagnóstico diferencial entre mastite aguda e carcinoma inflamatório pode ser confuso e erroneamente levar ao atraso no tratamento de neoplasia mamária. Sobre o diagnóstico e tratamento do carcinoma inflamatório, é correto afirmar:', options: ['Após ajustes dos fatores de risco, o carcinoma inflamatório tem a mesma sobrevida que o carcinoma de mama em sua apresentação clássica.', 'A biópsia do linfonodo sentinela não deve ser realizada.', 'Mesmo na presença de receptores hormonais positivos, a hormonioterapia adjuvante está contraindicada.', 'O diagnóstico de carcinoma inflamatório é clínico, dispensando a confirmação histopatológica.', 'No TNM da AJCC 8.ª edição, o carcinoma inflamatório é classificado com "T2d".'], correctIndex: 1 },
  { id: 'ufpr_2021_102_055', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Mastologia', text: 'Parte do programa de rastreamento de câncer de mama é identificar mulheres com maior chance de desenvolver a doença. Pessoas com risco vitalício maior ou igual a 20% (RR > 2,5) são consideradas de alto risco. Considerando apenas parentes de primeiro grau, qual dos seguintes antecedentes familiares aumenta o risco relativo para câncer de mama?', options: ['Carcinoma espinocelular de colo uterino.', 'Adenocarcinoma de pulmão.', 'Carcinoma papilífero de tireoide.', 'Carcinoma neuroendocrino de pâncreas.', 'Adenocarcinoma de ovário.'], correctIndex: 4 },
  { id: 'ufpr_2021_102_056', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Ginecologia', text: 'No ambulatório de infertilidade, a paciente J.K., de 32 anos, e seu marido F.L., de 34, vêm para atendimento. J.K. suspendeu o uso do contraceptivo combinado hormonal oral há 3 anos e, desde então, apresenta queixa de ciclos irregulares que chegam a atrasar 4 meses. Nega queixa de acne ou hirsutismo. Traz consigo alguns exames realizados em investigação na UBS: Histerossalpingografia - boa passagem de contraste e boa difusão em cavidade pélvica. Espermograma - 56 milhões por ml e 43% móveis. Ultrassom transvaginal com contagem de 23 folículos antrais em ovário direito e 15 em ovário esquerdo. A conduta para esse casal infértil é:', options: ['utilizar tratamentos medicamentosos como: letrozol, clomifeno, gonadotrofinas.', 'indicar a videolaparoscopia diagnóstica pela suspeita de endometriose.', 'propor a fertilização in vitro como tratamento, devido à baixa reserva ovariana apresentada pela paciente.', 'indicar a fertilização in vitro com injeção intracitoplasmática de espermatozoide (ICSI) pelo fator masculino grave.', 'recomendar tratamento à base de testosterona para melhorar a qualidade dos espermatozoides do marido.'], correctIndex: 0 },
  { id: 'ufpr_2021_102_057', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Ginecologia', text: 'Considerando o mesmo caso do casal J.K. e F.L., com ciclos irregulares e ultrassom transvaginal com contagem de 23 folículos antrais em ovário direito e 15 em ovário esquerdo, sobre o diagnóstico mais provável desse casal, é correto afirmar:', options: ['Não dispomos de informação suficiente para identificar a principal causa, e exames como FSH, estradiol, LH e progesterona são essenciais para esse diagnóstico.', 'O diagnóstico só poderá ser confirmado após análise de exame testosterona total, testosterona livre e S-Dhea.', 'Caso a paciente apresentasse um quadro de acne grave ou hirsutismo, a ecografia seria desnecessária e não haveria prejuízo no diagnóstico.', 'Confirmado o diagnóstico provável, a orientação é de tranquilizar a paciente e informar que infelizmente essa é uma condição irreversível.', 'Em caso de dor incapacitante ao menstruar, o diagnóstico está confirmado.'], correctIndex: 2 },
  { id: 'ufpr_2021_102_058', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Ginecologia', text: 'A paciente A.F., 27 anos, e seu marido L.O., 30 anos, vêm ao consultório com desejo gestacional. Usuária de contracepção hormonal desde os 18 anos de idade refere ter parado o uso há 1 ano e 6 meses. Desde então manteve ciclos regulares de 26 dias e com boa frequência sexual durante período fértil. A respeito da infertilidade, considere as seguintes afirmativas: 1. A endometriose, que tem como causa principal as aderências causadas e possível obstrução ou falha de função tubária, é uma doença multifatorial que pode levar à infertilidade. 2. Apesar do tabagismo ser associado com diferentes intercorrências na saúde do usuário, ele não tem relação direta com a infertilidade comprovada. 3. Fatores externos, como uma boa qualidade de vida com exercícios físicos, boa alimentação e boas noites de sono, são cruciais para o bom desenvolvimento do oócito e do espermatozoide. 4. Durante a investigação inicial de infertilidade, os exames necessários são: hormonais (FSH, LH, estradiol, progesterona, prolactina, TSH, T4l, testosterona livre, testosterona total, S-Dhea); imagem (ecografia transvaginal, histerossalpingografia); fator masculino (espermograma, ecografia bolsa escrotal e doppler de testículo). Assinale a alternativa correta.', options: ['Somente a afirmativa 2 é verdadeira.', 'Somente as afirmativas 1 e 3 são verdadeiras.', 'Somente as afirmativas 1 e 4 são verdadeiras.', 'Somente as afirmativas 2, 3 e 4 são verdadeiras.', 'As afirmativas 1, 2, 3 e 4 são verdadeiras.'], correctIndex: 1 },
  { id: 'ufpr_2021_102_059', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Ginecologia', text: 'No retorno após a investigação inicial do casal A.F. e L.O., recebemos o exame de histerossalpingografia com laudo: "trompas fixas e elevadas, com passagem de contraste bilateral". Em exame de imagem, consta a seguinte anotação no laudo: "sinais de aderências peritubárias bilateralmente". Além desses exames, o espermograma realizado há menos de 1 mês mostra 73 milhões de espermatozoides por ml e 43% móveis. A partir do caso descrito, é correto afirmar:', options: ['Sendo um casal jovem, em especial a mulher que tem menos de 35 anos, pode-se orientar o período fértil e recomendar tentativa espontânea por 6 meses.', 'Uma boa alternativa para aumentar as chances de gestação desse casal é utilizar indutores de ovulação como o citrato de clomifeno.', 'Considerando a passagem de contraste bilateral na histerossalpingografia, pode-se considerar o exame como normal e descartar o fator tubário como causa da infertilidade.', 'Apesar de ser uma cirurgia e, sendo assim, um procedimento invasivo, a videolaparoscopia pode ser uma boa opção terapêutica para esse casal.', 'A fertilização in vitro é uma opção descartada pelo fato de ser um casal muito jovem e também por se tratar de um tratamento de alto custo.'], correctIndex: 3 },
  { id: 'ufpr_2021_102_060', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Ginecologia', text: 'Após um ano da primeira consulta, A.F., agora com 28 anos, retorna à consulta com novas dúvidas. Apesar das condutas indicadas durante a última consulta, ela relata que não deram continuidade no tratamento e terminaram o relacionamento. Como A.F. tem como objetivo iniciar contracepção, é correto afirmar:', options: ['Sabendo que a mulher já nasce com todos os folículos e começa a liberar eles maduros (oócito secundário) mensalmente após a menarca, os métodos contraceptivos anovulatórios vão preservar os oócitos e, por consequência, manter a reserva ovariana e postergar a menopausa.', 'O DIU de cobre causa uma reação inflamatória importante na cavidade intrauterina e isso leva a um impedimento de implantação do embrião; sendo assim, classificado como um método abortivo.', 'Em relação aos métodos cirúrgicos (laqueadura e vasectomia), é necessário passar por atendimento multidisciplinar visando desencorajar a esterilização precoce.', 'O método contraceptivo hormonal à base de implante de etonogestrel tem a vantagem de ser um método que mantém a ovulação e, por consequência, mantém a libido aumentada durante o período ovulatório.', 'Os métodos à base de liberação de levonorgestrel intrauterino têm uma melhora significativa nas queixas de Tensão Pré-Menstrual (TPM) por ser um método anovulatório e assim diminuir as mudanças hormonais ocorridas após a ovulação.'], correctIndex: 2 },
  { id: 'ufpr_2021_102_061', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Saúde Coletiva', text: 'Em 2021, a Lei 10.216, também chamada de lei da Reforma Psiquiátrica, comemorou 20 anos de existência. Foi, sem dúvida, um marco na reformulação da política de saúde mental brasileira. Essa lei:', options: ['possibilitou a mudança de modelo de atenção, ampliando equipamentos comunitários e territoriais de saúde mental.', 'proibiu a internação em enfermarias psiquiátricas, garantindo que o tratamento seja comunitário.', 'foi um resultado das polícias públicas do Partido dos Trabalhadores, que incluíram populações vulnerabilizadas.', 'fomentou estratégias modernas de atenção como institutos de psiquiatria e de neuroimagem além de comunidades terapêuticas.', 'visou a garantia e o acesso a planos de saúde mais populares e acessíveis para o cuidado psiquiátrico.'], correctIndex: 0 },
  { id: 'ufpr_2021_102_062', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Saúde Coletiva', text: '"Reduzida em 26%, Saúde da Família poderia ajudar a frear Covid-19 em Curitiba-PR. São 63 equipes a menos do que há cinco anos; cobertura da população caiu de 43% para 31%". (Portal de Notícias Plural, 14 set 2020.) Enquanto a pandemia avançava, vimos priorização de investimentos em leitos, enquanto a atenção primária era preterida em relação a outras despesas que muitas vezes nem tinham relação com o campo da saúde. Nesse contexto, que atributos da atenção primária foram prejudicados?', options: ['Regionalização, foco familiar, intersetorialidade e ações matriciais.', 'Interdisciplinaridade, ações matriciais, acessibilidade e integralidade.', 'Coordenação do cuidado, transdisciplinaridade, determinantes sociais e longitudinalidade.', 'Integralidade, interdisciplinaridade, regionalização e primeiro contato.', 'Longitudinalidade, primeiro contato, integralidade e coordenação do cuidado.'], correctIndex: 4 },
  { id: 'ufpr_2021_102_063', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Saúde Coletiva', text: 'Com a pandemia de Covid-19, assistimos em 2020 e 2021, como resultado das abordagens governamentais, ao colapso da atenção à saúde no Brasil. Uma das expressões desse processo foi a superlotação dos leitos hospitalares, implicando alta mortalidade por falta de acesso e degradação das condições de atendimento. Sobre a estrutura hospitalar brasileira, assinale a alternativa correta.', options: ['Nas décadas de 1990 e 2000 ocorre uma importante expansão de leitos no Brasil, elevando a relação leitos/habitante no país acima dos patamares da década de 1980 e contribuindo para ampliação do acesso da população à Atenção Hospitalar.', 'A Atenção Hospitalar no Brasil após a implantação do SUS segue algumas tendências mundiais, como: redução do tempo médio de permanência hospitalar; aumento da densidade tecnológica e aumento do porte médio dos hospitais.', 'Com o desenvolvimento do SUS, tem se ampliado o acesso à Atenção Hospitalar, sendo que o número de internações pagas pelo SUS na década de 2000 foi superior ao número pago na década anterior (de 1990).', 'Um dos limites da Atenção Hospitalar no Brasil é o fato de a maioria dos hospitais serem privados, o que limita o acesso da população, visto que a grande maioria desses serviços não presta serviços para o SUS, privilegiando os planos privados.', 'O modelo atualmente adotado pelo SUS para pagamento das internações hospitalares é o pagamento prospectivo.'], correctIndex: 4 },
  { id: 'ufpr_2021_102_064', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Saúde Coletiva', text: 'A pandemia de Covid-19 teve repercussões importantes. Por um lado, a importância do SUS na garantia do acesso universal à saúde se tornou ainda mais evidente para grande parte da população. Por outro lado, o colapso da atenção à saúde também demonstrou vários limites enfrentados pelo sistema brasileiro ao longo de sua história e, principalmente, nos últimos anos. Grande parte desses limites decorre do financiamento do SUS. Sobre esse aspecto, assinale a alternativa correta:', options: ['No Brasil, o gasto público em saúde tem ficado em torno dos 4%, ou menos, do PIB, muito abaixo dos países europeus com sistemas universais e dos países da OCDE, que gastam em média entre 6 e 8% do PIB em saúde.', 'Uma das causas do subfinanciamento do SUS é o fato de ainda não haver uma definição legal dos valores mínimos a serem gastos, possibilitando que cada governante escolha quanto investir no sistema.', 'A Atenção Primária à Saúde (APS), por meio da Estratégia Saúde da Família (ESF), é o nível de atenção que apresentou maior expansão desde a criação do SUS, o que faz com que absorva a maior parte dos gastos federais em saúde.', 'O gasto total em saúde no Brasil como proporção do PIB tem ficado consideravelmente abaixo do percentual médio gasto pelos países europeus com sistemas universais e pelos países da OCDE.', 'Atualmente, a esfera federal é responsável pela maior parte dos gastos públicos em saúde no Brasil, o que faz com que medidas como a EC 95, que congela os gastos federais em políticas sociais por 20 anos, tenha efeitos negativos sobre o SUS.'], correctIndex: 0 },
  { id: 'ufpr_2021_102_065', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Saúde Coletiva', text: 'Um mecânico, na manutenção, realiza a limpeza de peças cheias de graxa com METIL-ETIL-CETONA (MEK). Durante seu exame periódico ocupacional, qual procedimento clínico-laboratorial de investigação o médico deve solicitar ou executar?', options: ['Excreção urinária de solventes (ácidos hipúrico e metil-hipúrico) para estudo de exposição (monitoramento biológico).', 'Exame neurológico completo, pois solventes orgânicos são causa comum de polineuropatias.', 'Teste neurológico de equilíbrio porque metais podem interferir nos tratos espinotalâmicos.', 'Hemograma com contagem de plaquetas e reticulócitos conforme estipula o quadro I da NR7.', 'Prova de função pulmonar para avaliar possível restrição por fibrose intersticial decorrente das graxas.'], correctIndex: 1 },
  { id: 'ufpr_2021_102_066', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Saúde Coletiva', text: 'Numa obra de engenharia civil com uso de marteletes pneumáticos, a avaliação ambiental demonstrou um nível equivalente de pressão sonora de 95 dB (NA). Foi considerada a jornada de 8 horas/dia e 44 horas/semana. Os trabalhadores utilizam protetores auditivos do tipo plug de inserção. Com relação à avaliação ocupacional da audição dos trabalhadores desse setor, considere as seguintes afirmativas: 1. Audiometria óssea será realizada sempre que houver alteração no exame de via aérea, podendo existir exame de limite de reconhecimento de fala (LRF), timpanometria, e sempre otoscopia prévia. 2. A via aérea deve ser avaliada nas frequências de 1.000, 2.000, 3000, 4.000 e 6.000 Hz. 3. A perda auditiva induzida por ruído é patognomônica quanto ao nexo ocupacional quando existe perda sensorioneural bilateral simétrica em uma ou mais frequências entre 3 e 8 kHz, em desenho de gota, com preservação das demais faixas. 4. A perda auditiva pelo ruído pode estar potencializada nas exposições concomitantes a vibrações de corpo inteiro e a solventes orgânicos (e também ao etilismo), gerando confusão diagnóstica mesmo em situações de ruídos abaixo do limite de tolerância. Assinale a alternativa correta.', options: ['Somente a afirmativa 2 é verdadeira.', 'Somente as afirmativas 1 e 4 são verdadeiras.', 'Somente as afirmativas 3 e 4 são verdadeiras.', 'Somente as afirmativas 1, 2 e 3 são verdadeiras.', 'As afirmativas 1, 2, 3 e 4 são verdadeiras.'], correctIndex: 1 },
  { id: 'ufpr_2021_102_067', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Medicina Legal', text: 'Um bombeiro militar do estado do Paraná em um combate a incêndio durante seu plantão de trabalho sofre queimadura de segundo grau na face e é atendido emergencialmente em um hospital privado. A partir do caso, considere as seguintes afirmativas: 1. Tendo em vista que o tratamento será de prazo prolongado, é de competência do médico que atendeu o paciente emitir um atestado de afastamento de no máximo 15 dias e encaminhá-lo para a perícia médica do INSS. 2. Por se tratar de atendimento em hospital que não é Unidade Sentinela do SUS, não há necessidade de registro compulsório do agravo no SINAN. 3. Um motivo que dispensa a notificação compulsória é que o SINAN classifica como acidente grave os que têm desfecho fatal e com mutilações, o que não engloba as queimaduras. 4. Este caso enquadra-se como acidente de trabalho para o SUS independentemente de o vínculo de trabalho ser formal ou informal. Assinale a alternativa correta.', options: ['Somente a afirmativa 4 é verdadeira.', 'Somente as afirmativas 1 e 2 são verdadeiras.', 'Somente as afirmativas 2 e 3 são verdadeiras.', 'Somente as afirmativas 1, 3 e 4 são verdadeiras.', 'As afirmativas 1, 2, 3 e 4 são verdadeiras.'], correctIndex: 0 },
  { id: 'ufpr_2021_102_068', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Saúde Coletiva', text: 'Um trabalhador da construção civil procura atendimento médico ambulatorial por lesões eritematodescamativas de mãos e pés, com algumas fissuras entre áreas de liquenificação. Queixa-se de quadro antigo, repetitivo, doloroso e às vezes com secreção serossanguínea. As unhas são engrossadas e quebradiças, esfarelando-se com facilidade. "Patch test" realizado antes desse trabalho foi positivo para dicromato de potássio. Sobre o caso, assinale a alternativa correta.', options: ['Para o diagnóstico de confirmação, está indicada a "intradermo reação de Mitsuda" (um pric –test).', 'Não deverá ser emitida a Comunicação de Acidente do Trabalho (CAT), pois para o reconhecimento do INSS não caracteriza acidente mas possivelmente uma doença relacionada ao trabalho.', 'O tratamento indicado é à base de emolientes, do tipo creme de ureia a 10%.', 'Com a lesão instalada e o nexo ocupacional, o médico deve caracterizar a atividade para "adicional de Insalubridade".', 'Trata-se do tipo 3 na classificação de Robert Schilling, e não de doença profissional.'], correctIndex: 4 },
  { id: 'ufpr_2021_102_069', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Infectologia', text: 'A esporotricose de transmissão felina (ETF) ou esporotricose de transmissão zoonótica apresenta-se como um surto epidêmico em expansão, sendo que no Brasil foram reportados milhares de casos humanos e felinos entre 2000 e 2021. A respeito do assunto, considere as seguintes afirmativas: 1. A infecção é causada por Sporothrix schenckii, um fungo dimórfico. 2. As principais formas clinicas da ETF são de natureza cutânea e linfocutânea. 3. O diagnóstico da ETF é por exame histopatológico, na maioria dos casos. 4. O tratamento da ETF é feito com o itraconazol. Assinale a alternativa correta.', options: ['Somente a afirmativa 1 é verdadeira.', 'Somente as afirmativas 1 e 3 são verdadeiras.', 'Somente as afirmativas 2 e 4 são verdadeiras.', 'Somente as afirmativas 2, 3 e 4 são verdadeiras.', 'As afirmativas 1, 2, 3 e 4 são verdadeiras.'], correctIndex: 2 },
  { id: 'ufpr_2021_102_070', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Infectologia', text: 'Um paciente de 61 anos com antecedentes de diabetes mellitus tipo II é internado em UTI de Curitiba, por complicações respiratórias relacionadas à COVID-19. Sob ventilação mecânica, recebe antibióticos e dexametasona, 6 mg/kg/dia. Após 7 dias de tratamento, apresenta picos febris, dor facial, lesão necrótica em palato, edema da pirâmide nasal e diplopia. Uma tomografia de seios da face revela velamento de seios paranasais e etmoidais. A curetagem de material obtido da ulceração de palato revelou em exame microscópico direto clarificado com hidróxido de potássio (KOH) hifas largas, não septadas, com ramificações em ângulo reto, compatíveis com fungos do gênero Mucorales. Baseado no caso relatado e nos exames apresentados, a principal hipótese diagnóstica é:', options: ['Rinosinusite bacteriana aguda.', 'Aspergilose invasiva.', 'Mucormicose.', 'Rinosinusite por COVID-19.', 'Rinosinusite invasiva por Fusarium spp.'], correctIndex: 2 },
  { id: 'ufpr_2021_102_071', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Saúde Coletiva', text: 'Para a reorganização dos serviços de saúde no Brasil, a 3.ª Conferência Nacional de Saúde, realizada em dezembro de 1963, teve a seguinte característica:', options: ['propôs técnicas de planejamento ascendente no setor saúde, dos municípios para estados e União.', 'apontou para a futura previdencialização do sistema de saúde, culminando, mais tarde, com a criação do INPS.', 'apresentou a necessidade de universalização do direito à saúde, o que foi colocado em prática nos anos subsequentes.', 'desconsiderou o desenvolvimento econômico como fator de melhoria nas condições de saúde da população.', 'teve ampla participação popular, com representantes dos movimentos sociais, além dos setores profissionais.'], correctIndex: 0 },
  { id: 'ufpr_2021_102_072', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Medicina de Família', text: 'Sabe-se que os modelos assistenciais em saúde são organizados de diferentes formas em diferentes países. Bárbara Starfield enfatiza que aqueles modelos com maior impacto nos indicadores de saúde são os que têm maior pontuação na avaliação da Atenção Primária à Saúde (APS). Para essa autora, têm scores mais altos em APS os sistemas de saúde que, entre outras, apresentam as seguintes características:', options: ['presença de pediatras e internistas, honorários profissionais dos médicos da APS de pelo menos 90% daqueles dos especialistas, atenção primária regulada.', 'financiamento por impostos, copagamento dos serviços, cadastramento dos pacientes.', 'especialistas representando menos de 70% dos médicos, sistema de urgência e emergência integrado à APS, presença de apoio matricial.', 'sistema de referência e contrarreferência efetivos, caráter bismarckiano do sistema de proteção social, ênfase na promoção da saúde.', 'presença de médicos de família ou generalistas, existência de cadastro de pacientes, departamentos acadêmicos de medicina de família fortes.'], correctIndex: 4 },
  { id: 'ufpr_2021_102_073', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Saúde Coletiva', text: 'O sanitarismo campanhista no Brasil, do início do século XX, teve no médico Oswaldo Cruz o seu mais ilustre representante. Ao assumir a Diretoria Geral de Saúde Pública (DGSP), esse médico prometeu erradicar as principais doenças infecciosas que atacavam a cidade do Rio de Janeiro. Nesse contexto, assinale a alternativa que apresenta duas doenças que foram negligenciadas nesse período.', options: ['Peste bubônica e varíola.', 'Febre amarela e peste bubônica.', 'Tuberculose e infecções intestinais.', 'Infecções intestinais e febre amarela.', 'Tuberculose e varíola.'], correctIndex: 2 },
  { id: 'ufpr_2021_102_074', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Saúde Coletiva', text: 'A Constituição Federal de 1988 previu que é livre à iniciativa privada atuar em saúde. Nesse contexto, assinale a alternativa que corresponde à atuação do setor privado em saúde no Brasil.', options: ['Empresas como as UNIMEDs são cooperativas médicas e têem finalidade lucrativa.', 'Os planos de saúde de autogestão são a modalidade de planos privados que predominam no país.', 'Cabe a uma agência reguladora fiscalizar as empresas de planos e seguros.', 'Os planos privados de saúde atuam de forma complementar ao Sistema Único de Saúde.', 'A existência dos planos e seguros privados de saúde representa maior saúde financeira para o Sistema Único de Saúde.'], correctIndex: 2 },
  { id: 'ufpr_2021_102_075', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Medicina de Família', text: 'Em relação ao genograma, é correto afirmar:', options: ['Sua construção deve ser detalhada desde o primeiro contato.', 'Sua construção é fruto da conferência familiar.', 'As notações relativas aos relacionamentos são opcionais.', 'Essa ferramenta permite identificar triângulos nas famílias.', 'Assuntos constrangedores devem ser evitados como forma de preservar o bom relacionamento com o paciente.'], correctIndex: 3 },
  { id: 'ufpr_2021_102_076', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Saúde Coletiva', text: 'Na avaliação da validade dos testes diagnósticos, considere as seguintes afirmativas: 1. A propriedade mais adequada a ser avaliada para interpretar um exame de RT PCR para COVID-19 negativo é a especificidade. 2. A solicitação de exames laboratoriais para indivíduos que foram triados previamente em consulta médica a partir de sinais e sintomas sugestivos melhora a especificidade do diagnóstico. 3. Estudos mostram que os vírus da dengue e do novo coronavírus possuem similaridade antigênica e, considerando essa constatação e a situação de pandemia de COVID-19, a realização de teste sorológico para dengue em regiões com baixa circulação dos quatro vírus da dengue (DENV1, DENV2, DENV3 e DENV4) diminui o valor preditivo positivo do teste. 4. Para a triagem da COVID-19 em atletas que irão participar de uma competição, são desejáveis testes com alta especificidade. Assinale a alternativa correta.', options: ['Somente a afirmativa 1 é verdadeira.', 'Somente as afirmativas 2 e 3 são verdadeiras.', 'Somente as afirmativas 1 e 4 são verdadeiras.', 'Somente as afirmativas 2, 3 e 4 são verdadeiras.', 'As afirmativas 1, 2, 3 e 4 são verdadeiras.'], correctIndex: 1 },
  { id: 'ufpr_2021_102_077', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Saúde Coletiva', text: 'O estudo "Safety and Efficacy of Single-Dose Ad26.COV2.S Vaccine against Covid-19" (N Engl J Med 2021; 384:2187-2201) é um ensaio de fase 3 internacional, randomizado, duplo-cego, controlado por placebo, que distribuiu aleatoriamente participantes em uma proporção de 1:1 para receber uma dose única de Ad26.COV2 ou placebo. Os desfechos primários foram a eficácia da vacina contra doença moderada a grave pelo novo coronavírus (Covid-19). A distribuição dos participantes por faixa etária foi de 66,5% (18-59 anos) e 33,5% (≥60 anos), semelhante entre os dois grupos. A eficácia da vacina para casos moderados/graves após 28 dias foi de 66,1% (IC95% 53,3-75,8) na faixa de 18-59 anos e 66,2% (IC95% 36,7-83,0) na faixa ≥60 anos. A partir dos dados apresentados e considerando os conceitos e metodologia dos ensaios clínicos, considere as seguintes afirmativas: 1. A partir dos dados apresentados, observa-se que a randomização segundo faixa etária foi eficiente. 2. Falhas na randomização dos participantes podem interferir na validade externa do estudo. 3. A eficácia representa a redução absoluta do risco e é calculada subtraindo da taxa de incidência de casos moderados e graves de Covid-19 do grupo controle a taxa de incidência no grupo que recebeu a intervenção. 4. Com a finalidade de estimar o número de indivíduos que devem receber a vacina para evitar um caso moderado ou grave de Covid, deve-se calcular o número necessário para tratar (NNT), que varia conforme a frequência do evento na população em que vai ser utilizada a intervenção. Assinale a alternativa correta.', options: ['Somente a afirmativa 1 é verdadeira.', 'Somente as afirmativas 2 e 3 são verdadeiras.', 'Somente as afirmativas 1 e 4 são verdadeiras.', 'Somente as afirmativas 2, 3 e 4 são verdadeiras.', 'As afirmativas 1, 2, 3 e 4 são verdadeiras.'], correctIndex: 2 },
  { id: 'ufpr_2021_102_078', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Saúde Coletiva', text: 'Um gráfico publicado na Revista Brasileira de Epidemiologia 2020 apresenta a situação da sífilis no estado de São Paulo, com curvas de tendência da taxa de detecção de sífilis adquirida e de sífilis adquirida incluindo gestantes, no período de 2011 a 2017, mostrando aumento contínuo da taxa de detecção ao longo do período. Levando em consideração os dados apresentados, assinale a alternativa correta.', options: ['Trata-se de um estudo epidemiológico analítico, do qual foram obtidos a taxa de incidência da sífilis adquirida em gestantes e recém-nascidos como variável dependente e o ano como variável de exposição.', 'A taxa de detecção é equivalente à taxa de incidência da doença, sendo que a taxa de detecção é utilizada pela vigilância epidemiológica no monitoramento da situação da sífilis na população geral (adquirida) e entre gestantes, utilizando para o cálculo de ambas as taxas a faixa etária correspondente.', 'O estudo ecológico que originou o gráfico é de séries temporais e sugere uma queda significativa das taxas a partir de 2013.', 'O Sistema de Informação de Agravos de Notificação (SINAN) é o sistema que permite o monitoramento da sífilis na população, e as estatísticas oriundas desse sistema podem ser calculadas para municípios, estados, regiões e total do país, disponíveis no DATASUS.', 'A sífilis adquirida é um agravo de notificação compulsória no Brasil desde 2005, enquanto a sífilis na gestação é de notificação obrigatória desde 1986.'], correctIndex: 3 },
  { id: 'ufpr_2021_102_079', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Medicina Legal', text: 'D.G, 72 anos, sexo feminino, foi admitida no hospital com diagnóstico de neutropenia febril pós-quimioterapia para tratamento de leucemia mieloide aguda. Apresentava insuficiência renal aguda com diálise diária, quadro de sepse de foco pulmonar, permanecendo pancitopênica com piora do quadro respiratório e óbito. O preenchimento das condições e causas do óbito foram preenchidas da seguinte maneira: Parte I a) Sepse grave. b) Neutropenia febril. c) Leucemia mieloide aguda. d) ---------------------------- Parte II Insuficiência renal aguda. Aplasia de medula pós-quimioterapia. Sobre o preenchimento da Declaração de Óbito, é correto afirmar:', options: ['A parte I foi preenchida corretamente, pois a causa básica foi a leucemia mieloide aguda, mas a parte II está incorreta.', 'Tanto a parte I quanto a parte II foram preenchidas corretamente.', 'A parte I foi preenchida incorretamente, pois a causa básica do óbito foi a neutropenia febril, devendo a leucemia mieloide aguda ser mencionada apenas na parte II.', 'A aplasia de medula pós-quimioterapia, mencionada na parte II, é uma causa externa prevista como evento adverso do tratamento e, dessa forma, deveria ser a causa básica e ser mencionada na parte I.', 'A insuficiência renal aguda é consequente à sepse grave e deveria ser registrada na letra "b" da parte I, enquanto a causa terminal deveria ser a neutropenia febril e deveria ser registrada na letra "d".'], correctIndex: 0 },
  { id: 'ufpr_2021_102_080', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Saúde Coletiva', text: 'Com o objetivo de avaliar a relação entre presença de sintomas depressivos e risco de morte em idosos residentes em município do Sul do Brasil, foi realizado um estudo longitudinal de base populacional com 1391 pessoas. Os sintomas depressivos foram avaliados através da Escala Geriátrica de Depressão, e o tempo de acompanhamento durou até o último contato ou registro da morte. A prevalência de sintomas depressivos foi de 23,5% (IC95% 20,4-26,9). Na análise bruta, o risco de mortalidade foi de 1,86 (IC 95% 1,35-2,55) para indivíduos com sintomas depressivos; após ajuste do modelo pelas variáveis sexo, educação, renda, trabalho remunerado, tabagismo, consumo de álcool, morbidades, uso de medicamentos, atividade física, deficiência, prejuízo cognitivo e índice de massa corporal, o risco de mortalidade foi de 1,67 (IC 95% 1,15-2,40). A partir das informações, é correto afirmar que se trata de um estudo:', options: ['de caso-controle, pois os idosos com depressão são os casos e os sem depressão, os controles.', 'de coorte longitudinal prospectivo controlado por variáveis de confusão na análise múltipla, em que a variável desfecho é a mortalidade.', 'transversal sobre depressão em idosos, em que a proporção de prevalência da doença foi de 23,5%.', 'ecológico de séries temporais, no qual o ano de nascimento da população observada é especificado e as taxas de depressão em cada grupo são comparadas.', 'de ensaio clínico, no qual se comparam níveis de depressão de acordo com a escala geriátrica e avalia-se a resposta de acordo com os cuidados oferecidos à população em geral na redução do desfecho morte.'], correctIndex: 1 },
  { id: 'ufpr_2021_102_081', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Pediatria', text: 'Um menino de 13 anos apresenta há 2 semanas área de descamação e maceração na região inguinal bilateral, associada a prurido. Refere que pratica esportes. No exame físico, apresenta uma placa eritematosa, com limites bem definidos e leve descamação na periferia, com centro mais claro. Considerando o caso apresentado, a conduta correta é:', options: ['coleta de material para bacterioscopia e cultura.', 'orientação para a suspensão temporária da atividade esportiva.', 'tratamento com cetoconazol por via oral.', 'tratamento com antibiótico por via oral.', 'tratamento com antifúngico tópico.'], correctIndex: 4 },
  { id: 'ufpr_2021_102_082', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Pediatria', text: 'As afecções da orelha são muito prevalentes na infância e merecem toda a atenção de clínicos e pediatras. Em relação às otites externas, assinale a alternativa correta.', options: ['O pH ácido do conduto é protetor das infecções do conduto auditivo externo.', 'Presença de hiperemia e abaulamento da membrana timpânica são frequentes, requerendo antibioticoterapia sistêmica na maioria dos casos.', 'O Streptococcus epidemidis é o agente infeccioso mais comum.', 'Manter o conduto auditivo externo sempre limpo e livre de cerume é importante na prevenção das otites externas.', 'São mais comuns nos meses de inverno e os vírus respiratórios são agentes etiológicos prevalentes.'], correctIndex: 0 },
  { id: 'ufpr_2021_102_083', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Pediatria', text: 'Em relação à paralisia cerebral espástica em crianças, é correto afirmar:', options: ['É tipicamente progressiva, com piora motora ao passar dos anos.', 'Entre os fatores de risco, encontram-se a injúria hipóxico-isquêmica e as malformações do encéfalo.', 'A espasticidade é um dos componentes da síndrome do neurônio motor inferior.', 'É o tipo mais raro de paralisia cerebral.', 'É secundária a lesões nos núcleos da base.'], correctIndex: 1 },
  { id: 'ufpr_2021_102_084', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Pediatria', text: 'Em relação ao edema cerebral na cetoacidose diabética na infância, assinale a alternativa correta.', options: ['Sua fisiopatologia é pouco conhecida e pode incluir a influência de osmóis idiogênicos, da hipoperfusão cerebral e efeitos diretos das cetonas.', 'Necessita ser confirmado por exames de imagem, pois frequentemente não apresenta manifestações clínicas.', 'Pode ser evitado com a administração rápida de bicarbonato, pois sua fisiopatologia encontra-se relacionada à acidose.', 'A hiperventilação terapêutica, após o paciente ser intubado, tem sido associada a melhores prognósticos.', 'É a segunda causa de mortalidade em cetoacidose diabética, após a sepse.'], correctIndex: 0 },
  { id: 'ufpr_2021_102_085', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Pediatria', text: 'Em relação aos reflexos primitivos e posturais da criança, o reflexo presente em uma criança normal aos 3 anos de idade é:', options: ['reflexo de Moro.', 'reflexo de preensão plantar.', 'reflexo tônico-cervical assimétrico.', 'marcha automática.', 'reflexo do paraquedista.'], correctIndex: 4 },
  { id: 'ufpr_2021_102_086', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Pediatria', text: 'Lactente chega no pronto-socorro, com febre e irritabilidade. A mãe refere que a urina está mais escura e fétida. Com base nos dados apresentados, assinale a alternativa correta em relação às condutas diagnóstica e terapêutica.', options: ['A coleta de urina por saco coletor é o padrão ouro para a confirmação diagnóstica.', 'Deve-se aguardar o resultado da urocultura para definir a conduta terapêutica.', 'O agente etiológico mais provável é a Klebsiella sp.', 'O exame da fita urinária, com positividade para nitrito e estearase leucocitária, sugere o diagnóstico de infecção urinária.', 'A droga de escolha para o tratamento empírico é a amoxicilina.'], correctIndex: 3 },
  { id: 'ufpr_2021_102_087', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Pediatria', text: 'Em maternidade, nasceu uma criança cuja mãe apresenta história de sífilis tratada durante o pré-natal (diagnóstico por VDRL 1:32). A mãe refere que fez uso de 2.400.000 UI de penicilina benzatina, durante 3 semanas seguidas (intervalos de 7 dias entre as doses). O parceiro não recebeu tratamento, mas a mãe refere que não teve mais relação sexual com ele. O VDRL da mãe no momento do parto da mãe foi 1:2, e do RN, após o nascimento, foi não reagente. Ao exame físico, o recém-nascido encontra-se assintomático. Com base nessas informações, assinale a alternativa correta.', options: ['Essa criança deve ser notificada como caso de sífilis congênita, e deve-se iniciar tratamento com penicilina.', 'Para definir a conduta terapêutica, é necessário completar a investigação com radiografia de ossos longos e análise do líquor.', 'O recém-nascido deve ser acompanhado laboratorialmente, com VDRL controles (1, 3, 6, 12 e 18 meses), até a obtenção de dois exames negativos.', 'Caso o líquor desse recém-nascido apresente 20 células e 80 mg/dL de proteína, ele deve receber 10 dias de penicilina cristalina.', 'Não há como definir e nem como tomar conduta nesse caso, pois o diagnóstico materno não foi confirmado com teste treponêmico durante o pré-natal.'], correctIndex: 2 },
  { id: 'ufpr_2021_102_088', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Pediatria', text: 'O crescimento é um processo dinâmico e necessita da utilização de gráficos para sua avaliação. Considerando as características conforme a fase do desenvolvimento e sexo, assinale a alternativa correta.', options: ['A puberdade é a fase de maior velocidade de crescimento.', 'Meninos e meninas crescem de modo semelhante durante a infância.', 'O estirão puberal possui maior duração nas meninas.', 'A desaceleração pré-puberal do crescimento é sinal de doença subjacente.', 'O estirão puberal inicia antes nos meninos.'], correctIndex: 1 },
  { id: 'ufpr_2021_102_089', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Pediatria', text: 'O pediatra é chamado para atender na sala de parto a um nascimento a termo. Trata-se de uma gestante com 40 semanas de idade gestacional, sem comorbidades, que realizou 12 consultas de pré-natal, não apresentou nenhuma intercorrência durante a gestação e evoluiu para parto vaginal. A ruptura das membranas amnióticas ocorreu 30 minutos antes, observando-se a presença de líquido amniótico meconial fluido. Ao nascimento, o recém-nascido apresenta choro forte e tônus em flexão. Com base nos dados apresentados e considerando as Diretrizes de Reanimação Neonatal da Sociedade Brasileira de Pediatria – 2021, considere as seguintes afirmativas: 1. Recomenda-se que o obstetra proceda à aspiração de vias aéreas do recém-nascido logo após o nascimento. 2. O clampeamento tardio do cordão umbilical está indicado e deve ser realizado entre 1 e 3 minutos. 3. Recomenda-se a realização dos passos iniciais da reanimação e, se o recém-nascido apresentar boa vitalidade, levá-lo assim que possível para permanecer em contato pele-a-pele com sua mãe. 4. Para redução da hipotermia neonatal, recomenda-se manter a temperatura ambiente da sala de parto e da sala de reanimação entre 20 e 23 ºC e garantir que as portas permaneçam fechadas para minimizar as correntes de ar. Assinale a alternativa correta.', options: ['Somente a afirmativa 2 é verdadeira.', 'Somente as afirmativas 1 e 3 são verdadeiras.', 'Somente as afirmativas 2 e 4 são verdadeiras.', 'Somente as afirmativas 1, 3 e 4 são verdadeiras.', 'As afirmativas 1, 2, 3 e 4 são verdadeiras.'], correctIndex: 0 },
  { id: 'ufpr_2021_102_090', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Pediatria', text: 'Recém-nascido a termo, com peso de nascimento de 3.100 g, encontra-se no alojamento conjunto com 48 horas de vida. Ao realizar o Teste do Coraçãozinho (oximetria de pulso), observou-se uma SpO2 na mão direita de 92% e no pé direito de 90%. O teste foi repetido após 1 hora, confirmando os mesmos valores. O bebê está bem, sugando o seio materno, mantendo frequência respiratória de 48 irpm, pulsos arteriais centrais e periféricos normais e não há sopros cardíacos. Com base nos dados apresentados, qual é a conduta correta?', options: ['Aguardar 24 horas, repetir a oximetria de pulso e, conforme o resultado, definir a alta hospitalar do recém-nascido.', 'Dar alta hospitalar ao recém-nascido, sem necessidade nova avaliação, pois os limites de SpO2 obtidos podem ser considerados normais para a faixa etária.', 'Dar alta hospitalar ao recém-nascido e encaminhá-lo para a realização de ecocardiograma ou avaliação de cardiologista pediátrico no primeiro mês de vida.', 'Solicitar um ecocardiograma e não dar alta hospitalar ao recém-nascido até que esse exame seja realizado.', 'Transferir o recém-nascido para UTI neonatal e iniciar infusão de prostraglandina-1 (PGE1), até que se defina o diagnóstico da cardiopatia.'], correctIndex: 3 },
  { id: 'ufpr_2021_102_091', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Pediatria', text: 'Em relação à asma na criança, assinale a alternativa correta.', options: ['A asma é uma doença crônica que geralmente tem início em idade escolar.', 'O tratamento do refluxo gastroesofágico geralmente melhora o controle da asma.', 'A presença de sibilos persistentes com deformidade do tórax é sugestiva de asma.', 'Teste cutâneo alérgico positivo e eosinofilia indicam resposta inadequada ao uso de corticoide inalatório.', 'A resposta ao tratamento com corticoide é sugestiva de asma.'], correctIndex: 4 },
  { id: 'ufpr_2021_102_092', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Pediatria', text: 'Escolar, 7 anos de idade, com quadro de tosse crônica. Quanto ao diagnóstico diferencial da tosse crônica na infância e com base em dados da anamnese ou achados do exame físico, a correlação adequada é:', options: ['Antecedente de encefalopatia hipôxico-isquêmica – broncoaspirações.', 'Ausculta de estertores grossos – rinossinusite crônica.', 'Hipocratismo digital – asma.', 'Déficit pondero-estatural – rinite alérgica.', 'Ausculta de sibilos simétrica – aspiração de corpo estranho.'], correctIndex: 0 },
  { id: 'ufpr_2021_102_093', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Pediatria', text: 'Sobre transtorno de déficit de atenção/hiperatividade (TDAH), é correto afirmar:', options: ['Ocorre simultaneamente com outros transtornos emocionais, transtornos endocrinológicos, comportamentais e de aprendizagem.', 'Na faixa etária pediátrica, são contraindicados os psicoestimulantes e antidepressivos.', 'Crianças afetadas geralmente apresentam insucesso acadêmico, problemas de relacionamento interpessoal e baixa autoestima, com resolução na vida adulta.', 'É o terceiro transtorno neurocomportamental mais comum da infância.', 'O TDAH é caracterizado por desatenção, incluindo aumento da distração e dificuldade em manter a atenção; controle de impulso pobre e diminuição da capacidade de autoinibição; hiperatividade e inquietação motora.'], correctIndex: 4 },
  { id: 'ufpr_2021_102_094', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Pediatria', text: 'Lactente de 45 dias de vida é trazido à consulta por seus pais por apresentar teste do pezinho alterado para fibrose cística. O primeiro valor de tripsinogênio imunorreativo realizado com 15 dias está alterado e o segundo, realizado há 3 dias, está normal. Qual é a orientação correta para o caso?', options: ['Encerrar o caso, pois o segundo exame tem resultado normal.', 'Fazer teste de condutividade.', 'Solicitar pesquisa da variante genética delta F508.', 'Solicitar teste do suor.', 'Investigar fibrose cística se na evolução apresentar sinais e sintomas sugestivos.'], correctIndex: 3 },
  { id: 'ufpr_2021_102_095', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Pediatria', text: 'Escolar com antecedente de asma apresenta tosse seca, com vômitos e febre, há 10 dias. Refere que o quadro iniciou com rouquidão. Nunca foi internado e está com as vacinas em dia. Ao exame físico, apresenta hiperemia de membrana timpânica bilateral com ausência de cone luminoso à direita, sibilos e estertores finos em lobo inferior direito. Está em uso de amoxicilina há 5 dias, houve melhora da rouquidão, mas persiste tosse e febre. Qual é o diagnóstico para o caso?', options: ['Pneumonia por Mycoplasma.', 'Exacerbação de asma induzida por vírus.', 'Bronquite bacteriana protraída.', 'Tuberculose.', 'Coqueluche.'], correctIndex: 0 },
  { id: 'ufpr_2021_102_096', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Pediatria', text: 'Recém-nascido do sexo masculino, idade gestacional de 34 semanas, escores de Apgar de 8 e 9, peso de nascimento de 1.800 g. Nas primeiras 24 horas de vida, evoluiu com sinais de desconforto respiratório e necessitou de cuidados em unidade de terapia intensiva neonatal. Recebeu alta com 20 dias de vida devido às intercorrências. Considerando que a criança nasceu durante a pandemia de Covid-19, a conduta correta em relação à coleta do teste de triagem neonatal é:', options: ['orientar à família para comparecer na unidade de saúde para realizar a coleta do teste após a alta hospitalar.', 'coletar o teste logo após o nascimento e repetir com 4 a 6 semanas de vida devido à prematuridade.', 'coletar o teste na maternidade no momento da alta hospitalar, uma vez que muitas unidades básicas de saúde fecharam por causa da pandemia de Covid-19, e repetir com 2 meses de vida devido à prematuridade.', 'coletar o teste nas primeiras 48 horas de vida e repetir com 7 dias de vida devido às intercorrências.', 'coletar o teste com 3 a 5 dias de vida e repetir no momento da alta hospitalar.'], correctIndex: 4 },
  { id: 'ufpr_2021_102_097', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Pediatria', text: 'Paciente de 5 anos, com queixa de astenia, fadiga, manchas roxas pelo corpo e dor nas pernas há 2 semanas. Ao exame físico, hipocorada +++/4+, hidratada, ativa e reativa. Temperatura axilar 38,5 ºC. Ausculta pulmonar sem alterações. Bulhas cardíacas rítmicas, 2 tempos, com presença de sopro sistólico ++/4+. Fígado palpável a 5 cm do rebordo costal, e baço a 6 cm. Petéquias e equimoses em membros inferiores. Hemograma evidenciando Hb 4,0 g/dL, VCM 84 fL, leucócitos 600x103/uL, plaquetas 2.000/uL. O diagnóstico provável é:', options: ['anemia aplástica severa.', 'deficiência de B12.', 'endocardite bacteriana.', 'leucemia linfocítica aguda.', 'trombocitopenia primária imune.'], correctIndex: 3 },
  { id: 'ufpr_2021_102_098', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Pediatria', text: 'A respeito da esferocitose hereditária (EH), considere as seguintes afirmativas: 1. A EH é uma doença de caráter genético, do tipo autossômica dominante, sendo pouco frequente sua manifestação na forma autossômica recessiva. 2. Alterações de determinadas proteínas da membrana do eritrócito, como a anquirina, espectrinas, banda 3 e proteína 4.2, estão na origem da diminuição da resistência osmótica dos esferócitos, sendo o defeito da anquirina o mais comum. 3. Esplenomegalia está presente na maioria dos casos, porém não há correlação entre o tamanho do baço e a gravidade da anemia. 4. Déficit de crescimento é uma das indicações de esplenectomia, que deve ser realizada, se possível, somente após os 5 anos de idade. Assinale a alternativa correta.', options: ['Somente a afirmativa 4 é verdadeira.', 'Somente as afirmativas 1 e 3 são verdadeiras.', 'Somente as afirmativas 2 e 3 são verdadeiras.', 'Somente as afirmativas 1, 2 e 4 são verdadeiras.', 'As afirmativas 1, 2, 3 e 4 são verdadeiras.'], correctIndex: 4 },
  { id: 'ufpr_2021_102_099', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Pediatria', text: 'Lactente admitido no pronto atendimento com história de fezes líquidas e febre. Ao exame, sonolento, alternando nível de consciência com irritabilidade, e sinais clínicos de desidratação. A gasometria arterial apresenta: pH= 7,02/pCO2 = 12 mmHg/pO2 = 180 mmHg/HCO3= 6 mEq/L / BE = –22/Sat O2 = 97%. Qual é o distúrbio ácido básico na gasometria?', options: ['Acidose respiratória.', 'Alcalose respiratória.', 'Acidose metabólica.', 'Acidose mista.', 'Alcalose metabólica.'], correctIndex: 2 },
  { id: 'ufpr_2021_102_100', banca: 'UFPR', cycle: 'Ciclo Clínico', subject: 'Pediatria', text: 'J.M., 4 anos, previamente hígido, após tentativa de ingerir um comprimido de paracetamol, apresentou tosse, evolui com cianose e foi optado por acionar o SAMU. Ao chegar no local, o médico do SAMU encontra a criança em parada cardiorrespiratória (PCR). Realizada ressuscitação cardiopulmonar (RCP) por 15 minutos até retorno da frequência cardíaca e pulso central. Levando em consideração os dados apresentados, assinale a alternativa correta.', options: ['A equipe que está prestando atendimento deve realizar como primeira medida a intubação traqueal.', 'A provável causa da PCR foi por hipóxia devido à aspiração de corpo estranho.', 'A RCP sem via aérea avançada com mais de um socorrista deve ser realizada 30 compressões para 2 ventilações.', 'Se os socorristas realizaram a orientação adequada da RCP, eles devem ter utilizado no mínimo 2 doses de epinefrina no período da reanimação.', 'Não é necessário checar o ritmo durante as avaliações a cada 2 minutos pois o paciente foi encontrado pela equipe em assistolia.'], correctIndex: 1 },
];
